CREATE TABLE users_to_vendors
(
	id serial,
	user_id integer NOT NULL,
	vendor_id integer DEFAULT NULL,
	CONSTRAINT pk_users_to_vendors PRIMARY KEY (id)
	, CONSTRAINT fk_users_to_vendors_to_question FOREIGN KEY (user_id) REFERENCES users (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_users_to_vendors_to_vendor FOREIGN KEY (vendor_id) REFERENCES organizations (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_users_to_vendors_user ON users_to_vendors (user_id);
CREATE INDEX i_users_to_vendors_vendor ON users_to_vendors (vendor_id);
